'use client';

import { useState, useEffect } from 'react';
import type { Invoice } from '@/lib/db/types';

function InvoiceRow({
  invoice,
  onUpdate,
}: {
  invoice: InvoiceType;
  onUpdate: (u: { paymentLink?: string; status?: string }) => void;
}) {
  const [editing, setEditing] = useState(false);
  const [link, setLink] = useState(invoice.payment_link ?? '');
  const [status, setStatus] = useState<'draft' | 'sent' | 'paid'>(invoice.status);

  const save = () => {
    onUpdate({ paymentLink: link || undefined, status });
    setEditing(false);
  };

  return (
    <div className="flex justify-between items-start border border-gray-200 rounded-lg p-3 gap-2">
      <div className="min-w-0 flex-1">
        <p className="font-medium">{invoice.description}</p>
        <p className="text-sm text-gray-600">${(invoice.amount_cents / 100).toFixed(2)}</p>
        {editing ? (
          <div className="mt-2 space-y-2">
            <input
              type="url"
              value={link}
              onChange={(e) => setLink(e.target.value)}
              placeholder="Payment link"
              className="w-full px-2 py-1 text-sm border rounded"
            />
            <select
              value={status}
              onChange={(e) => setStatus(e.target.value as 'draft' | 'sent' | 'paid')}
              className="px-2 py-1 text-sm border rounded"
            >
              <option value="draft">Draft</option>
              <option value="sent">Sent</option>
              <option value="paid">Paid</option>
            </select>
            <div className="flex gap-2">
              <button onClick={save} className="text-primary text-sm font-medium">Save</button>
              <button onClick={() => setEditing(false)} className="text-gray-500 text-sm">Cancel</button>
            </div>
          </div>
        ) : (
          <button onClick={() => setEditing(true)} className="text-primary text-xs mt-1 hover:underline">
            Edit
          </button>
        )}
      </div>
      <span className={`px-2 py-0.5 rounded text-xs font-medium shrink-0 ${
        invoice.status === 'paid' ? 'bg-green-100 text-green-800' :
        invoice.status === 'sent' ? 'bg-blue-100 text-blue-800' : 'bg-gray-100 text-gray-800'
      }`}>
        {invoice.status}
      </span>
    </div>
  );
}
import { useParams, useRouter } from 'next/navigation';
import Link from 'next/link';
import {
  FaEnvelope,
  FaPhone,
  FaMapMarkerAlt,
  FaFileInvoiceDollar,
  FaPaperPlane,
  FaTrash,
} from 'react-icons/fa';
import type { Lead, Communication, Invoice as InvoiceType, EmailTemplate } from '@/lib/db/types';
import { LEAD_STATUS_LABELS } from '@/lib/db/types';

export default function LeadDetailPage() {
  const params = useParams();
  const router = useRouter();
  const id = params.id as string;
  const [lead, setLead] = useState<Lead & { communications: Communication[]; invoices: Invoice[] } | null>(null);
  const [templates, setTemplates] = useState<EmailTemplate[]>([]);
  const [loading, setLoading] = useState(true);
  const [showEmail, setShowEmail] = useState(false);
  const [showInvoice, setShowInvoice] = useState(false);
  const [emailSubject, setEmailSubject] = useState('');
  const [emailBody, setEmailBody] = useState('');
  const [selectedTemplate, setSelectedTemplate] = useState('');
  const [sending, setSending] = useState(false);
  const [invoiceDesc, setInvoiceDesc] = useState('');
  const [invoiceAmount, setInvoiceAmount] = useState('');
  const [invoicePaymentLink, setInvoicePaymentLink] = useState('');
  const [savingInvoice, setSavingInvoice] = useState(false);

  useEffect(() => {
    Promise.all([
      fetch(`/api/crm/leads/${id}`).then((r) => r.json()),
      fetch('/api/crm/templates').then((r) => r.json()),
    ])
      .then(([leadData, templatesData]) => {
        setLead(leadData);
        setTemplates(templatesData);
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [id]);

  const applyTemplate = (t: EmailTemplate, paymentLinkOverride?: string) => {
    const vars: Record<string, string> = {
      name: lead?.name ?? '',
      address: lead?.address ?? '',
      email: lead?.email ?? '',
      phone: lead?.phone ?? '',
      payment_link: paymentLinkOverride ?? '',
    };
    let subj = t.subject;
    let body = t.body;
    for (const [k, v] of Object.entries(vars)) {
      subj = subj.replace(new RegExp(`{{${k}}}`, 'g'), v);
      body = body.replace(new RegExp(`{{${k}}}`, 'g'), v);
    }
    setEmailSubject(subj);
    setEmailBody(body);
  };

  const insertPaymentLink = (link: string) => {
    setEmailBody((prev) => prev.replace(/\{\{payment_link\}\}/g, link));
  };

  const handleSendEmail = async () => {
    if (!lead) return;
    setSending(true);
    try {
      const res = await fetch('/api/crm/send-email', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          leadId: lead.id,
          to: lead.email,
          subject: emailSubject,
          body: emailBody,
          recordCommunication: true,
        }),
      });
      const data = await res.json();
      if (data.success) {
        setShowEmail(false);
        setEmailSubject('');
        setEmailBody('');
        router.refresh();
        const updated = await fetch(`/api/crm/leads/${id}`).then((r) => r.json());
        setLead(updated);
      } else {
        alert(data.message || 'Failed to send');
      }
    } catch (e) {
      alert('Failed to send email');
    } finally {
      setSending(false);
    }
  };

  const handleCreateInvoice = async () => {
    if (!lead || !invoiceDesc || !invoiceAmount) return;
    setSavingInvoice(true);
    try {
      const amountCents = Math.round(parseFloat(invoiceAmount) * 100);
      const res = await fetch('/api/crm/invoices', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          leadId: lead.id,
          description: invoiceDesc,
          amountCents,
          paymentLink: invoicePaymentLink || null,
        }),
      });
      const data = await res.json();
      if (data.id) {
        setShowInvoice(false);
        setInvoiceDesc('');
        setInvoiceAmount('');
        setInvoicePaymentLink('');
        const updated = await fetch(`/api/crm/leads/${id}`).then((r) => r.json());
        setLead(updated);
      } else {
        alert(data.error || 'Failed to create invoice');
      }
    } catch {
      alert('Failed to create invoice');
    } finally {
      setSavingInvoice(false);
    }
  };

  const handleDelete = async () => {
    if (!confirm(`Delete lead "${lead?.name}"? This cannot be undone.`)) return;
    try {
      const res = await fetch(`/api/crm/leads/${id}`, { method: 'DELETE' });
      if (!res.ok) throw new Error('Failed to delete');
      router.push('/crm');
    } catch {
      alert('Failed to delete lead');
    }
  };

  const updateLeadStatus = async (status: Lead['status']) => {
    if (!lead) return;
    const res = await fetch(`/api/crm/leads/${id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status }),
    });
    if (res.ok) {
      const updated = await res.json();
      setLead({ ...lead, ...updated });
    }
  };

  const formatDate = (d: string) =>
    new Date(d).toLocaleString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: 'numeric',
      minute: '2-digit',
    });

  if (loading || !lead) {
    return (
      <div className="text-gray-500">
        {loading ? 'Loading...' : 'Lead not found'}
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <Link href="/crm" className="text-primary hover:underline">← Back to leads</Link>
        <button
          type="button"
          onClick={handleDelete}
          className="text-red-600 hover:text-red-800 text-sm font-medium flex items-center gap-1.5"
        >
          <FaTrash /> Delete lead
        </button>
      </div>

      <div className="grid lg:grid-cols-3 gap-6">
        {/* Lead info */}
        <div className="lg:col-span-2 space-y-4">
          <div className="bg-white rounded-xl border border-gray-200 p-6">
            <h2 className="text-lg font-bold text-primary mb-4">{lead.name}</h2>
            <div className="space-y-2 text-sm">
              <div className="flex items-center gap-2">
                <FaEnvelope className="text-gray-400 w-4" />
                <a href={`mailto:${lead.email}`} className="text-primary hover:underline">{lead.email}</a>
              </div>
              <div className="flex items-center gap-2">
                <FaPhone className="text-gray-400 w-4" />
                <a href={`tel:${lead.phone}`} className="text-primary hover:underline">{lead.phone}</a>
              </div>
              {lead.address && (
                <div className="flex items-center gap-2">
                  <FaMapMarkerAlt className="text-gray-400 w-4" />
                  <span>{lead.address}</span>
                </div>
              )}
            </div>
            {lead.lawn_size && <p className="mt-2 text-sm text-gray-600">Lawn: {lead.lawn_size} sq ft</p>}
            {lead.driveway_length && <p className="text-sm text-gray-600">Driveway: {lead.driveway_length} ft</p>}
            {lead.notes && <p className="mt-2 text-sm text-gray-600 italic">Notes: {lead.notes}</p>}
          </div>

          {/* Communications */}
          <div className="bg-white rounded-xl border border-gray-200 p-6">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-semibold text-primary">Communications</h3>
              <button
                onClick={() => { setShowEmail(true); setShowInvoice(false); }}
                className="flex items-center gap-2 bg-primary text-white px-3 py-1.5 rounded-lg text-sm font-medium hover:bg-primary-dark"
              >
                <FaPaperPlane /> Send email
              </button>
            </div>
            {lead.communications.length === 0 ? (
              <p className="text-sm text-gray-500">No emails sent yet.</p>
            ) : (
              <div className="space-y-3">
                {lead.communications.map((c) => (
                  <div key={c.id} className="border-l-2 border-primary pl-3 py-1">
                    <p className="font-medium text-sm">{c.subject || '(No subject)'}</p>
                    <p className="text-xs text-gray-500">{formatDate(c.sent_at)}</p>
                    <p className="text-sm text-gray-600 mt-1 line-clamp-2">{c.body}</p>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Invoices */}
          <div className="bg-white rounded-xl border border-gray-200 p-6">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-semibold text-primary">Invoices</h3>
              <button
                onClick={() => { setShowInvoice(true); setShowEmail(false); }}
                className="flex items-center gap-2 bg-primary text-white px-3 py-1.5 rounded-lg text-sm font-medium hover:bg-primary-dark"
              >
                <FaFileInvoiceDollar /> New invoice
              </button>
            </div>
            {lead.invoices.length === 0 ? (
              <p className="text-sm text-gray-500">No invoices yet.</p>
            ) : (
              <div className="space-y-3">
                {lead.invoices.map((inv) => (
                  <InvoiceRow
                    key={inv.id}
                    invoice={inv}
                    onUpdate={async (updates) => {
                      const res = await fetch(`/api/crm/invoices/${inv.id}`, {
                        method: 'PATCH',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify(updates),
                      });
                      if (res.ok) {
                        const updated = await fetch(`/api/crm/leads/${id}`).then((r) => r.json());
                        setLead(updated);
                      }
                    }}
                  />
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Sidebar: status + quick actions */}
        <div className="space-y-4">
          <div className="bg-white rounded-xl border border-gray-200 p-6">
            <h3 className="font-semibold text-primary mb-3">Status</h3>
            <select
              value={lead.status}
              onChange={(e) => updateLeadStatus(e.target.value as Lead['status'])}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm"
            >
              {Object.entries(LEAD_STATUS_LABELS).map(([v, l]) => (
                <option key={v} value={v}>{l}</option>
              ))}
            </select>
          </div>
          <div className="bg-white rounded-xl border border-gray-200 p-6">
            <p className="text-xs text-gray-500">Form: {lead.form_type}</p>
            <p className="text-xs text-gray-500 mt-1">Created {formatDate(lead.created_at)}</p>
          </div>
        </div>
      </div>

      {/* Email modal */}
      {showEmail && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl max-w-2xl w-full max-h-[90vh] overflow-y-auto p-6">
            <h3 className="text-lg font-bold text-primary mb-4">Send email to {lead.name}</h3>
            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-700 mb-1">Template</label>
              <select
                value={selectedTemplate}
                onChange={(e) => {
                  setSelectedTemplate(e.target.value);
                  const t = templates.find((x) => x.id === e.target.value);
                  if (t) applyTemplate(t);
                }}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg"
              >
                <option value="">Choose a template...</option>
                {templates.map((t) => (
                  <option key={t.id} value={t.id}>{t.name}</option>
                ))}
              </select>
            </div>
            {lead.invoices.some((i) => i.payment_link) && (
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-1">Insert payment link from invoice</label>
                <select
                  onChange={(e) => {
                    const inv = lead.invoices.find((i) => i.id === e.target.value);
                    if (inv?.payment_link) insertPaymentLink(inv.payment_link);
                  }}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                >
                  <option value="">Select invoice...</option>
                  {lead.invoices.filter((i) => i.payment_link).map((inv) => (
                    <option key={inv.id} value={inv.id}>
                      {inv.description} - ${(inv.amount_cents / 100).toFixed(2)}
                    </option>
                  ))}
                </select>
              </div>
            )}
            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-700 mb-1">Subject</label>
              <input
                type="text"
                value={emailSubject}
                onChange={(e) => setEmailSubject(e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                placeholder="Email subject"
              />
            </div>
            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-700 mb-1">Body</label>
              <textarea
                value={emailBody}
                onChange={(e) => setEmailBody(e.target.value)}
                rows={10}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg font-mono text-sm"
                placeholder="Email body. Use {{name}}, {{address}}, {{payment_link}} for placeholders."
              />
            </div>
            <div className="flex gap-3">
              <button
                onClick={() => setShowEmail(false)}
                className="px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50"
              >
                Cancel
              </button>
              <button
                onClick={handleSendEmail}
                disabled={sending || !emailSubject || !emailBody}
                className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark disabled:opacity-50"
              >
                {sending ? 'Sending...' : 'Send email'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Invoice modal */}
      {showInvoice && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl max-w-lg w-full p-6">
            <h3 className="text-lg font-bold text-primary mb-4">New invoice for {lead.name}</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                <input
                  type="text"
                  value={invoiceDesc}
                  onChange={(e) => setInvoiceDesc(e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  placeholder="e.g., Initial payment - Season Pass"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Amount ($)</label>
                <input
                  type="number"
                  step="0.01"
                  value={invoiceAmount}
                  onChange={(e) => setInvoiceAmount(e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  placeholder="e.g., 350"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Payment link (paste from Stripe, etc.)</label>
                <input
                  type="url"
                  value={invoicePaymentLink}
                  onChange={(e) => setInvoicePaymentLink(e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  placeholder="https://..."
                />
              </div>
            </div>
            <div className="flex gap-3 mt-6">
              <button
                onClick={() => setShowInvoice(false)}
                className="px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50"
              >
                Cancel
              </button>
              <button
                onClick={handleCreateInvoice}
                disabled={savingInvoice || !invoiceDesc || !invoiceAmount}
                className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark disabled:opacity-50"
              >
                {savingInvoice ? 'Creating...' : 'Create invoice'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
